CREATE TABLE "ShopSettings" ("shop" TEXT NOT NULL PRIMARY KEY, "locale" TEXT NOT NULL DEFAULT 'it', "plan" TEXT NOT NULL DEFAULT 'free', "carbonPricePerKg" REAL NOT NULL DEFAULT 0.30, "carbonNeutralEnabled" BOOLEAN NOT NULL DEFAULT false, "checkoutBadgeEnabled" BOOLEAN NOT NULL DEFAULT true, "defaultCarrier" TEXT NOT NULL DEFAULT 'standard', "monthlyOrderLimit" INTEGER NOT NULL DEFAULT 100, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL);
CREATE TABLE "SustainabilityOrder" ("id" TEXT NOT NULL PRIMARY KEY, "shop" TEXT NOT NULL, "orderGid" TEXT NOT NULL, "orderName" TEXT, "countryCode" TEXT, "postalCodePrefix" TEXT, "weightGrams" INTEGER NOT NULL, "distanceKm" REAL NOT NULL, "emissionsKg" REAL NOT NULL, "baselineEmissionsKg" REAL NOT NULL, "savingsKg" REAL NOT NULL DEFAULT 0, "carrier" TEXT NOT NULL, "packagingCode" TEXT NOT NULL, "offsetSelected" BOOLEAN NOT NULL DEFAULT false, "offsetAmount" REAL NOT NULL DEFAULT 0, "calculatedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "SustainabilityOrder_shop_fkey" FOREIGN KEY ("shop") REFERENCES "ShopSettings" ("shop") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "ProductStat" ("id" TEXT NOT NULL PRIMARY KEY, "orderId" TEXT NOT NULL, "productGid" TEXT, "title" TEXT NOT NULL, "category" TEXT, "quantity" INTEGER NOT NULL, "allocatedEmissionsKg" REAL NOT NULL, CONSTRAINT "ProductStat_orderId_fkey" FOREIGN KEY ("orderId") REFERENCES "SustainabilityOrder" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "WebhookReceipt" ("id" TEXT NOT NULL PRIMARY KEY, "topic" TEXT NOT NULL, "shop" TEXT NOT NULL, "receivedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "SustainabilityOrder_shop_orderGid_key" ON "SustainabilityOrder"("shop", "orderGid");
CREATE INDEX "SustainabilityOrder_shop_calculatedAt_idx" ON "SustainabilityOrder"("shop", "calculatedAt");
CREATE INDEX "ProductStat_productGid_idx" ON "ProductStat"("productGid");